async (params, browser) => {
  // Open Wikipedia page
  await browser.open(`${params.article_url}`)

  // Wait for page to load
  await browser.waitForSelector('#firstHeading, h1, #catlinks, #mw-subcategories, #mw-pages', 15000)

  // Let page render
  await browser.wait(1500)

  // Scroll to categories
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(1500)

  // Extract categories
  const categories_data = await browser.evaluate(`const titleEl = document.querySelector('#firstHeading, h1'); const categories = []; const catLinks = document.querySelectorAll('#catlinks li a, #mw-normal-catlinks li a'); catLinks.forEach(function(a) { categories.push({ name: a.textContent.trim(), url: a.href }); }); const subcategories = []; const subcatEls = document.querySelectorAll('#mw-subcategories li a, .CategoryTreeItem a'); subcatEls.forEach(function(a) { subcategories.push({ name: a.textContent.trim(), url: a.href }); }); const pages = []; const pageEls = document.querySelectorAll('#mw-pages li a'); pageEls.forEach(function(a) { pages.push({ title: a.textContent.trim(), url: a.href }); }); const pagesCountEl = document.querySelector('#mw-pages p, #mw-pages h2 + p'); return { title: titleEl ? titleEl.textContent.trim() : '', category_count: categories.length, categories: categories.slice(0, 30), subcategory_count: subcategories.length, subcategories: subcategories.slice(0, 30), pages_in_category: pages.slice(0, 30), pages_info: pagesCountEl ? pagesCountEl.textContent.trim() : '', url: window.location.href }`)

  return categories_data
}
